#include <bits/stdc++.h>
using namespace std;
struct Node{
    int x,y;
}c,f;
string s[11];
int di[4][2]={{-1,0},{0,1},{1,0},{0,-1}},df=0,dc=0;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    for(int i=0;i<10;i++){
        cin>>s[i];
        for(int j=0;j<10;j++){
            if(s[i][j]=='F')
                f={i,j};
            else if(s[i][j]=='C')
                c={i,j};
        }
    }
    int tot=0;
    while(1){
        tot++;
        if(tot>1e7){
            tot=0;
            break;
        }
        int xx=f.x+di[df][0],yy=f.y+di[df][1];
        if(xx>=0 && xx<10 && yy>=0 && yy<10 && s[xx][yy]!='*')
            f={xx,yy};
        else
            df=(df+1)%4;
        xx=c.x+di[dc][0],yy=c.y+di[dc][1];
        if(xx>=0 && xx<10 && yy>=0 && yy<10 && s[xx][yy]!='*')
            c={xx,yy};
        else
            dc=(dc+1)%4;
        if(f.x==c.x && f.y==c.y)
            break;
    }
    printf("%d",tot);
    return 0;
}
